

<?php $__env->startSection('page-title', 'Verifikasi Campaign'); ?><?php $__env->startSection('content'); ?><h1 class="text-3xl font-bold">Verifikasi Campaign</h1><div class="mt-6 space-y-4"><?php $__currentLoopData = $campaigns; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $campaign): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><div class="card"><div class="flex flex-col justify-between gap-4 md:flex-row"><div><p class="font-bold"><?php echo e($campaign->title); ?></p><p class="text-sm text-slate-600"><?php echo e($campaign->category->name); ?> · <?php echo e($campaign->status); ?> · Rp <?php echo e(number_format($campaign->target_amount,0,',','.')); ?></p><p class="text-sm"><?php echo e($campaign->short_description); ?></p></div><form method="post" action="<?php echo e(route('admin.campaigns.verify',$campaign)); ?>" class="flex flex-col gap-2 md:w-80"><?php echo csrf_field(); ?> <?php echo method_field('patch'); ?><textarea class="input" name="admin_notes" placeholder="Catatan verifikasi"></textarea><div class="flex gap-2"><button class="btn-primary flex-1" name="action" value="approve">Approve</button><button class="btn-secondary flex-1" name="action" value="reject">Reject</button></div></form></div></div><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></div><div class="mt-6"><?php echo e($campaigns->links()); ?></div><?php $__env->stopSection(); ?>

